        Debug.Log("\n--- Steps to Publish ---");
        Debug.Log("1. Create an Itch.io account");
        Debug.Log("2. Click 'Upload New Project'");
        Debug.Log("3. Fill in game details");
        Debug.Log("4. Upload your build files");
        Debug.Log("5. Set price (free or paid)");
        Debug.Log("6. Publish!");

        Debug.Log("\n--- What to Include ---");
        Debug.Log("✅ Game executable (.exe, .app, .x86_64)");
        Debug.Log("✅ Game data folder");
